+// Flush processes any remaining buffered data as a line.
+func (d *URLDetector) Flush() {
+	d.mu.Lock()
+	defer d.mu.Unlock()
+
+	if len(d.buffer) > 0 {
+		lineStr := string(d.buffer)
+		if d.callback != nil {
+			urls := URLPattern.FindAllString(lineStr, -1)
+			for _, url := range urls {
+				d.callback(url)
+			}
+		}
+		d.buffer = nil
+	}
+}
